__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"TYPES",{enumerable:!0,get:function(){return n}});const n={Manifestor:{type:'Manifestor',emoji:'\ud83d\udd25',oran:'~%9',aura:'\u0130tici, kapal\u0131',signature:'Huzur',notSelf:'\xd6fke',strategy:'Bildir (informing)',rolePrimary:'Ba\u015flat\u0131c\u0131',shortDesc:'Yeni d\xf6ng\xfcleri ba\u015flatmak i\xe7in tasarlanm\u0131\u015f ba\u011f\u0131ms\u0131z bir ba\u015flat\u0131c\u0131. Auras\u0131 kar\u015f\u0131dakini iter; bu sayede etkisini geni\u015f bir alana ta\u015f\u0131r.',longDesc:'Manifestorlar, kimsenin izni olmadan ba\u015flatma g\xfcc\xfcne sahip nadir tiplerdir. Sakral merkezleri tan\u0131ms\u0131zd\u0131r; s\xfcrd\xfcr\xfclebilir i\u015f enerjisine sahip de\u011fildirler ama harekete ge\xe7irme, ba\u015flatma ve etki b\u0131rakma kapasiteleri y\xfcksektir. \xc7evrelerini \xf6fkelendirmemek i\xe7in stratejileri "bildirmek"tir; bir \u015fey yapmadan \xf6nce bundan etkilenecek olan ki\u015filere k\u0131saca haber vermek auray\u0131 yumu\u015fat\u0131r ve diren\xe7le kar\u015f\u0131la\u015fmalar\u0131n\u0131 engeller. Do\u011fru ya\u015fad\u0131klar\u0131nda huzur (peace) hissederler; yanl\u0131\u015f ya\u015fad\u0131klar\u0131nda ise \xf6fke (anger) ve yaln\u0131zl\u0131k ortaya \xe7\u0131kar.',pracicalTips:['Bir \u015fey yapmadan \xf6nce \xe7evreni bilgilendir; izin de\u011fil, haber.','\xc7ocuklukta kontrol alt\u0131na al\u0131nmaya kar\u015f\u0131 korumac\u0131 bir kabuk geli\u015ftirmi\u015f olabilirsin; bunu fark et.','Enerjini koruman i\xe7in tek ba\u015f\u0131na \xe7al\u0131\u015fma alanlar\u0131n olsun.','Dinlenme d\xf6ng\xfclerine alan a\xe7; s\xfcrekli \xfcretim i\xe7in tasarlanmad\u0131n.'],keywords:['Ba\u015flatma','Etki','Ba\u011f\u0131ms\u0131zl\u0131k','\u0130mpakt']},'Jenerat\xf6r':{type:'Jenerat\xf6r',emoji:'\ud83c\udf31',oran:'~%37',aura:'A\xe7\u0131k, sarmalay\u0131c\u0131',signature:'Tatmin',notSelf:'Hayal k\u0131r\u0131kl\u0131\u011f\u0131',strategy:'Yan\u0131t vermeyi bekle',rolePrimary:'Ya\u015fam ustas\u0131',shortDesc:'Sakralin saf g\xfcc\xfc. Sevdi\u011fi i\u015fe verdi\u011finde t\xfckenmez bir enerji kayna\u011f\u0131; yan\u0131t verdi\u011finde do\u011fru hayat\u0131 bulur.',longDesc:'Jenerat\xf6rler, d\xfcnyan\u0131n yap\u0131 ta\u015f\u0131d\u0131r. Tan\u0131ml\u0131 sakral merkez sayesinde s\xfcrd\xfcr\xfclebilir bir i\u015f ve ya\u015fam enerjisine sahiptirler. Auras\u0131 a\xe7\u0131k ve sarmalay\u0131c\u0131d\u0131r; kar\u015f\u0131la\u015ft\u0131\u011f\u0131 her \u015feye sakralinden bir "uh-huh / un-uh" sesiyle yan\u0131t verir. Beynin "iyi fikir" demesi yetmez; bedeninin yan\u0131t verdi\u011fine bakmal\u0131d\u0131r. Do\u011fru hayat\u0131 ya\u015fad\u0131\u011f\u0131nda derin bir tatmin (satisfaction) hissi vard\u0131r; aksi halde s\xfcrekli hayal k\u0131r\u0131kl\u0131\u011f\u0131 (frustration) ya\u015far. Mastery (ustal\u0131k) yolu, sevdikleri \u015feyleri tekrarlaya tekrarlaya derinle\u015fmektir.',pracicalTips:['Beden yan\u0131t\u0131n\u0131 dinle: g\xf6\u011fs\xfcnden gelen "evet" ya da "hay\u0131r" hissini takip et.','\xc7evrendekilerden evet/hay\u0131rl\u0131 sorular sormalar\u0131n\u0131 iste.','Sevmedi\u011fin i\u015fe enerji koyma; aksi halde hayal k\u0131r\u0131kl\u0131\u011f\u0131 kronikle\u015fir.','Ak\u015fam yata\u011fa girmeden \xf6nce bedenini ger\xe7ek anlamda yor.'],keywords:['Yan\u0131t','Sakral','Ustal\u0131k','Tatmin']},'Manifesting Jenerat\xf6r':{type:'Manifesting Jenerat\xf6r',emoji:'\u26a1',oran:'~%33',aura:'A\xe7\u0131k, sarmalay\u0131c\u0131',signature:'Tatmin',notSelf:'Hayal k\u0131r\u0131kl\u0131\u011f\u0131 & \xf6fke',strategy:'Yan\u0131t ver, sonra bildir',rolePrimary:'\xc7ok katmanl\u0131 yarat\u0131c\u0131',shortDesc:'H\u0131zl\u0131, \xe7ok y\xf6nl\xfc ve atlamal\u0131 bir Jenerat\xf6r t\xfcr\xfc. Ayn\u0131 anda birden fazla \u015feyi yapabilir; s\xfcreci atlama hediyesine sahiptir.',longDesc:'Manifesting Jenerat\xf6rler, tan\u0131ml\u0131 sakralleri ile bir motorun (Sakral, Heart, Solar Plexus ya da Root) bo\u011faza ba\u011fland\u0131\u011f\u0131 melez tiplerdir. Bu sayede hem yan\u0131t verirler hem de manifest ederler. Tek bir \u015feye s\u0131k\u0131\u015f\u0131p kalmaktansa birden fazla ilgi alan\u0131n\u0131 paralel y\xfcr\xfctmek i\xe7in yarat\u0131lm\u0131\u015flard\u0131r. Ad\u0131mlar\u0131 atlayarak ilerlemek do\u011fal hediyeleridir; bu y\xfczden s\u0131kl\u0131kla "biraz da geri d\xf6n\xfcp \u015fu ad\u0131m\u0131 yapmam gerekiyor" dedikleri olur. Stratejileri \xf6nce yan\u0131t vermek (sakralden), ard\u0131ndan harekete ge\xe7meden \xf6nce ilgili ki\u015fileri bilgilendirmektir.',pracicalTips:['Birden fazla projeyi paralel y\xfcr\xfctmek hatan de\u011fil, hediyendir.','Sakral yan\u0131t\u0131n olmayan bir \u015feye atlama; i\xe7sel s\u0131k\u0131\u015f\u0131kl\u0131\u011fa neden olur.','H\u0131z\u0131n\u0131 yava\u015flatanlara kar\u015f\u0131 sab\u0131rla de\u011fil, bilgilendirerek hareket et.','Ad\u0131mlar\u0131 atlad\u0131\u011f\u0131nda geri d\xf6n\xfcp dolduraca\u011f\u0131n yerleri not et.'],keywords:['\xc7oklu y\xf6n','H\u0131z','Atlama','Manifestasyon']},'Projekt\xf6r':{type:'Projekt\xf6r',emoji:'\ud83d\udd2e',oran:'~%21',aura:'Odakl\u0131, derin',signature:'Ba\u015far\u0131',notSelf:'Ac\u0131l\u0131k',strategy:'Davet bekle (ya\u015fam, sevgi, kariyer)',rolePrimary:'Rehber & y\xf6netici',shortDesc:'\u0130nsanlar\u0131 ve sistemleri okuma uzman\u0131. Davet edildi\u011finde derin g\xf6r\xfcleriyle ba\u015fkalar\u0131n\u0131n enerjisini do\u011fru y\xf6ne y\xf6nlendirir.',longDesc:'Projekt\xf6rler, sakral merkezi tan\u0131ms\u0131z olan ve ya\u015fam enerjisini Jenerat\xf6rlerin auras\u0131ndan \xf6rnekleyerek hareket eden tiplerdir. Auras\u0131 odakl\u0131 ve n\xfcfuz edicidir; kar\u015f\u0131lar\u0131ndaki ki\u015fiyi derinlemesine okurlar. Yenilik\xe7i sistemler, ba\u015fkalar\u0131n\u0131n enerjisini nas\u0131l y\xf6nlendirece\u011fini g\xf6rme yetenekleri y\xfcksektir. Ancak bu g\xf6r\xfcleri ancak davet edildiklerinde de\u011fer kazan\u0131r. Davet edilmeden enerjilerini \xf6ne s\xfcrmeleri ac\u0131l\u0131k (bitterness) yarat\u0131r. Do\u011fru ya\u015fand\u0131\u011f\u0131nda ba\u015far\u0131 (success) ve tan\u0131nma gelir. Daha az \xe7al\u0131\u015f\u0131p daha \xe7ok dinlenmek i\xe7in tasarlanm\u0131\u015flard\u0131r.',pracicalTips:['Hayat\u0131n b\xfcy\xfck alanlar\u0131nda (sevgi, i\u015f, ta\u015f\u0131nma) davet bekle.','Auray\u0131 tan\u0131: insanlar seni sordu\u011funda g\xf6zlerini k\u0131s ve g\xf6rmeye izin ver.','G\xfcnl\xfck dinlenme zaman\u0131 ay\u0131r; sakral de\u011fil, projekt\xf6r enerjisiyle ya\u015f\u0131yorsun.','Tan\u0131nmak istiyorsan \xf6nce kendini tan\u0131; i\xe7sel yetkinli\u011fin de\u011fer kazand\u0131k\xe7a davet artar.'],keywords:['G\xf6r\xfc','Rehberlik','Davet','Tan\u0131nma']},'Reflekt\xf6r':{type:'Reflekt\xf6r',emoji:'\ud83c\udf15',oran:'~%1',aura:'\xd6rnekleyici, ak\u0131c\u0131',signature:'S\xfcrpriz / \u015fa\u015fk\u0131nl\u0131k',notSelf:'Hayal k\u0131r\u0131kl\u0131\u011f\u0131',strategy:'28 g\xfcnl\xfck ay d\xf6ng\xfcs\xfcn\xfc bekle',rolePrimary:'Topluluk aynas\u0131',shortDesc:'Hi\xe7bir merkezi tan\u0131ml\u0131 de\u011fil. \xc7evresinin enerjisini \xf6rnekler ve topluma ayna tutar; do\u011fru toplulukta par\u0131ldar.',longDesc:'Reflekt\xf6rler, dokuz merkezin hi\xe7biri tan\u0131ml\u0131 olmayan ve d\xfcnyan\u0131n yaln\u0131zca y\xfczde birini olu\u015fturan en nadir tiptir. Auras\u0131 \xf6rnekleyici ve ge\xe7irgendir; ba\u015fkalar\u0131n\u0131n enerjisini ve \xe7evreyi i\xe7ine al\u0131r, yans\u0131t\u0131r. Bu y\xfczden bulunduklar\u0131 topluluk ve mekan onlar i\xe7in her \u015feyden \xf6nemlidir. B\xfcy\xfck kararlarda h\u0131zl\u0131 karar vermek yerine bir tam ay d\xf6ng\xfcs\xfcn\xfc (yakla\u015f\u0131k 28 g\xfcn) beklemeleri ve bu s\xfcrede farkl\u0131 insanlarla konu\u015farak karar\u0131 i\xe7sel olarak s\xfczmeleri tavsiye edilir. Do\u011fru ya\u015fad\u0131klar\u0131nda hayat onlar\u0131 s\xfcrpriz ve hayretle (surprise) doldurur.',pracicalTips:['Hayat\u0131ndaki insanlar\u0131 ve mekan\u0131 dikkatle se\xe7; her \u015fey budur.','B\xfcy\xfck kararlarda 28 g\xfcn bekle; bu s\xfcreyi farkl\u0131 dostlarla konu\u015farak ge\xe7ir.','Ay haritan\u0131 takip et; her g\xfcn farkl\u0131 bir merkezini deneyimleyebilirsin.','Yorgun ya da bo\u015f hissetti\u011finde yaln\u0131z kal; \xf6rnekledi\u011fin enerjiden ar\u0131n.'],keywords:['Ayna','\xd6rnekleme','Ay','Topluluk']}}},426,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"AUTHORITIES",{enumerable:!0,get:function(){return n}});const n={emotional:{key:'emotional',name:'Duygusal Yetki',emoji:'\ud83c\udf0a',shortDesc:'Solar Plexus tan\u0131ml\u0131. Net karar yoktur; bir duygu dalgas\u0131ndan ge\xe7erek netli\u011fe ula\u015f\u0131l\u0131r. Karar ancak dalga duruldu\u011funda do\u011frudur.',howToDecide:['Bir karar kar\u015f\u0131s\u0131nda an\u0131nda "evet" deme; \xfczerinde uyu.','Y\xfcksek noktada heyecanla ya da d\xfc\u015f\xfck noktada \xfcz\xfcnt\xfcyle karar verme.','Birka\xe7 g\xfcn boyunca karara farkl\u0131 duygu durumlar\u0131nda bak; ayn\u0131 kal\u0131yor mu?','Netlik ancak duygusal sal\u0131n\u0131m\u0131n s\xf6n\xfcmlenmesiyle gelir.'],caution:'Aceleci kararlar duygusal yetkiyi atlat\u0131r; pi\u015fmanl\u0131k yarat\u0131r.'},sacral:{key:'sacral',name:'Sakral Yetki',emoji:'\ud83c\udf31',shortDesc:'Sakral tan\u0131ml\u0131, Solar Plexus tan\u0131ms\u0131z. Anl\u0131k beden yan\u0131t\u0131yla karar verilir: g\xf6\u011f\xfcsten gelen "uh-huh" / "un-uh".',howToDecide:['Kar\u015f\u0131na \xe7\u0131kan \u015feye anl\u0131k beden tepkini dinle.','Beynin de\u011fil, karn\u0131n\u0131n/sakralinin sesini takip et.','Sana evet/hay\u0131rl\u0131 sorular sordurarak yan\u0131t \xe7\u0131kmas\u0131na izin ver.','Yan\u0131t\u0131n yoksa o anda do\u011fru karar mevcut de\u011fildir.'],caution:'Beynin gerek\xe7eleri sakral yan\u0131t\u0131n yerine ge\xe7emez.'},splenic:{key:'splenic',name:'Splenik Yetki',emoji:'\ud83e\udeb6',shortDesc:'Spleen tan\u0131ml\u0131, Solar Plexus ve Sakral tan\u0131ms\u0131z. Anl\u0131k, sessiz, f\u0131s\u0131lt\u0131 gibi i\xe7g\xfcd\xfcsel bir fark\u0131ndal\u0131k.',howToDecide:['\u015eu an hissedilen sezgiyi takip et; tekrar etmez.','\u0130lk i\xe7sel sinyal genellikle do\u011frudur.','Korkudan \xe7ok mevcut an\u0131n g\xfcvenli\u011fine odakl\u0131 bir fark\u0131ndal\u0131kt\u0131r.','H\u0131zl\u0131, sessiz ve tekrar etmeyen bilgiyi yakala.'],caution:'Splenik yetki sessizdir; g\xfcr\xfclt\xfc ve kalabal\u0131kta ka\xe7\u0131r\u0131l\u0131r.'},ego:{key:'ego',name:'Kalp / Ego Yetki',emoji:'\ud83d\udc51',shortDesc:'Heart merkezi tan\u0131ml\u0131, Solar Plexus, Sakral ve Spleen tan\u0131ms\u0131z. Karar\u0131 kalbin/iradenin sesi verir: "ben istiyorum mu?".',howToDecide:['Karar\u0131 duyarken kalbinden ne \xe7\u0131k\u0131yor: istek mi, yorgunluk mu?','Konu\u015furken sesli d\xfc\u015f\xfcn; a\u011fz\u0131ndan \xe7\u0131kan kelimelere kulak ver.','Kalbin "var m\u0131y\u0131m?" sorusuna verdi\u011fi yan\u0131t\u0131 dinle.','\u0130rade ve ki\u015fisel arzu burada otoritedir.'],caution:'Ba\u015fkalar\u0131n\u0131 memnun etmek i\xe7in s\xf6z vermeye kar\u015f\u0131 dikkatli ol.'},'self-projected':{key:'self-projected',name:'Kendine Projekte Yetki',emoji:'\ud83e\ude9e',shortDesc:'G-Center tan\u0131ml\u0131 ve bo\u011faza ba\u011fl\u0131; alt motorlar tan\u0131ms\u0131z. Karar konu\u015fmaktan, kendi sesini duymaktan \xe7\u0131kar.',howToDecide:['G\xfcvendi\u011fin bir dostla y\xfcksek sesle konu\u015f.','S\xf6ylerken sesinin tonu yumu\u015fad\u0131\u011f\u0131nda ya da g\xfc\xe7lendi\u011finde dikkat et.','Kar\u015f\u0131ndaki tavsiye vermesin; sadece dinlesin.','Do\u011fru y\xf6n, kendi sesinden \xe7\u0131kan kimli\u011fin ger\xe7e\u011fidir.'],caution:'\u0130\xe7inden konu\u015fmak yetmez; sesli duymak gerekir.'},mental:{key:'mental',name:'Zihinsel / \xc7evresel Yetki',emoji:'\ud83c\udf2c\ufe0f',shortDesc:'Sadece bilin\xe7li alan ve ge\xe7irgen merkezler. Karar tek ba\u015f\u0131na de\u011fil, do\u011fru \xe7evre ve do\u011fru ses tahtalar\u0131 arac\u0131l\u0131\u011f\u0131yla \xe7\u0131kar.',howToDecide:['Birden fazla g\xfcvendi\u011fin ki\u015fiyle konu\u015f.','Do\u011fru fiziksel mekan ve do\u011fru insanlar netli\u011fe g\xf6t\xfcr\xfcr.','Karara tek ba\u015f\u0131na oturma; ge\xe7irgen merkezler aldatabilir.','S\xf6zc\xfckler d\xf6kerken hangi ortam\u0131n seni destekledi\u011fini fark et.'],caution:'Zihin karar veremez; ses tahtas\u0131 gerekir.'},lunar:{key:'lunar',name:'Lunar / Ay Yetki (Reflekt\xf6r)',emoji:'\ud83c\udf15',shortDesc:'Hi\xe7bir merkez tan\u0131ml\u0131 de\u011fil. B\xfcy\xfck kararlar 28 g\xfcnl\xfck tam ay d\xf6ng\xfcs\xfc beklenerek al\u0131n\u0131r.',howToDecide:['\xd6nemli bir karara kar\u015f\u0131 28 g\xfcn bekle.','Ay d\xf6ng\xfcs\xfcn\xfcn her g\xfcn\xfcnde farkl\u0131 bir merkez aktive olur; karar\u0131 bu s\xfcre\xe7te s\xfczersin.','Bu s\xfcre\xe7te farkl\u0131 insanlarla konu\u015f; ayn\u0131 \u015feyi tekrar tekrar duy.','Hayretle / s\xfcrprizle ilerlemek do\u011fru y\xf6ne i\u015farettir.'],caution:'Ay d\xf6ng\xfcs\xfcn\xfc atlama; aceleci kararlar derin yorgunluk yarat\u0131r.'},none:{key:'none',name:'Belirsiz Yetki',emoji:'\xb7',shortDesc:'Yetki tespit edilemedi.',howToDecide:[],caution:''}}},427,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"LINES",{enumerable:!0,get:function(){return n}}),Object.defineProperty(e,"PROFILES",{enumerable:!0,get:function(){return l}});const n={1:{number:1,name:'Ara\u015ft\u0131rmac\u0131',shortDesc:'Sa\u011flam temeller arar; emin olmak i\xe7in ara\u015ft\u0131r\u0131r, okur, derinle\u015fir. Bilgi g\xfcvenli\u011fin temelidir.',shadow:'Yetersizlik korkusu, hi\xe7 bitmeyen haz\u0131rl\u0131k d\xf6nemi.'},2:{number:2,name:'M\xfcnzevi / Do\u011fal Yetenek',shortDesc:'Yaln\u0131zl\u0131\u011fa ihtiyac\u0131 vard\u0131r; kendi alan\u0131nda hediyesini do\u011fal olarak ta\u015f\u0131r. Davet edilmeyi bekler.',shadow:'\xc7a\u011f\u0131r\u0131lmadan g\xf6r\xfcnmek, kendi s\xfcrecini yorumlamak.'},3:{number:3,name:'Deneyimci / \u015eehit',shortDesc:'Hayat\u0131 \xe7arp\u0131\u015farak \xf6\u011frenir; deneme-yan\u0131lma onun bilgeli\u011fidir. Hatalar veridir, su\xe7 de\u011fil.',shadow:'Su\xe7luluk, ka\xe7\u0131nma, "yine olmad\u0131" duygusu.'},4:{number:4,name:'F\u0131rsat\xe7\u0131 / A\u011f \u0130nsan\u0131',shortDesc:'Hayat\u0131 yak\u0131n \xe7evresi ve dostluklar\u0131 \xfczerinden ilerletir. Bir sonraki ad\u0131ma elindekini b\u0131rakmadan ge\xe7er.',shadow:'Dostlu\u011fa ba\u011f\u0131ml\u0131l\u0131k, yenisini haz\u0131rlamadan eskiyi b\u0131rakma korkusu.'},5:{number:5,name:'Yans\u0131t\u0131c\u0131 / Pratik \xc7\xf6z\xfcc\xfc',shortDesc:'\xdczerine yans\u0131yanlarla \xe7a\u011f\u0131r\u0131l\u0131r. Pratik \xe7\xf6z\xfcmler sunar; krizde aranan ki\u015fidir. Karizmas\u0131 fonksiyoneldir.',shadow:'Yans\u0131t\u0131lan beklentilerin y\xfck\xfc, yanl\u0131\u015f anla\u015f\u0131lma korkusu.'},6:{number:6,name:'Rol Modeli / Bilge',shortDesc:'\xdc\xe7 evreli ya\u015fam: 0\u201330 deneme, 30\u201350 \xe7at\u0131dan izleme, 50+ rol modelli\u011fi. Otantik \xf6rnek olur.',shadow:'\xc7at\u0131dan kopuk hissetme, m\xfckemmellik bask\u0131s\u0131.'}},l={'1/3':{key:'1/3',name:'Ara\u015ft\u0131rmac\u0131 / \u015eehit',theme:'Hayat\u0131 denemek i\xe7in derin temeller arar',shortDesc:'\xd6nce sa\u011flam zemin kurar, sonra deneyerek \xf6\u011frenir. Hatalar onun verisidir; bilgelik buradan do\u011far.',longDesc:'Bu profil, i\xe7sel olarak ya\u015far (ki\u015fisel s\xfcrecine y\xf6nelir). \xd6nce her \u015feyi ara\u015ft\u0131rma i\xe7g\xfcd\xfcs\xfc ta\u015f\u0131r; ard\u0131ndan deneme-yan\u0131lma yoluyla bilgisini do\u011frular. S\xfcrt\xfc\u015fmesiz bir hayat onun i\xe7in dura\u011fan bir hayatt\u0131r; \xe7arp\u0131\u015fmadan b\xfcy\xfcmez. \u0130li\u015fkiler ve projeler kurulur, \xe7\xf6z\xfcl\xfcr, yeniden kurulur. Sa\u011flam temel ile cesur deneme aras\u0131nda sal\u0131n\u0131r.'},'1/4':{key:'1/4',name:'Ara\u015ft\u0131rmac\u0131 / F\u0131rsat\xe7\u0131',theme:'Sa\u011flam temeli yak\u0131n \xe7evresine ta\u015f\u0131yan ara\u015ft\u0131rmac\u0131',shortDesc:'Bilgiyi g\xfcvendi\u011fi insan a\u011f\u0131 \xfczerinden payla\u015f\u0131r. \u0130\xe7sel kap\u0131 d\u0131\u015fsal a\u011f arac\u0131l\u0131\u011f\u0131yla a\xe7\u0131l\u0131r.',longDesc:'Bu profil, i\xe7sel olarak ya\u015far. \xd6nce sa\u011flam bilgi temelini kurar, sonra bunu yak\u0131n \xe7evresinde payla\u015f\u0131r. Hayat de\u011fi\u015fimleri \xe7o\u011funlukla "tan\u0131d\u0131\u011f\u0131n bir tan\u0131d\u0131k" \xfczerinden gelir. Ba\u011flant\u0131lar ya\u015famsald\u0131r; a\u011f sa\u011flamsa kap\u0131lar t\u0131k\u0131rdar.'},'2/4':{key:'2/4',name:'M\xfcnzevi / F\u0131rsat\xe7\u0131',theme:'Do\u011fal yetene\u011fini yak\u0131n \xe7evresi ke\u015ffeder',shortDesc:'Yaln\u0131zl\u0131\u011f\u0131nda hediyesini ta\u015f\u0131r; \xe7evresi onu g\xf6r\xfcr ve \xe7a\u011f\u0131r\u0131r. \xc7a\u011fr\u0131 geldi\u011finde sahneye \xe7\u0131kar.',longDesc:'Bu profil, i\xe7sel olarak ya\u015far. Do\u011fas\u0131nda bir hediye ta\u015f\u0131r ama bunu \xf6\u011frenmi\u015f de\u011fildir; yaln\u0131z zamanlar\u0131nda ortaya \xe7\u0131kar. Yak\u0131n dostlar, akrabalar, eski tan\u0131d\u0131klar onu fark eder ve \xe7a\u011f\u0131r\u0131r. \xc7a\u011fr\u0131lmadan kendini g\xf6stermek bu profili yorar; \xe7a\u011fr\u0131yla harekete ge\xe7ti\u011finde parlar.'},'2/5':{key:'2/5',name:'M\xfcnzevi / Yans\u0131t\u0131c\u0131',theme:'Yaln\u0131z hediyesi pratik bir kurtar\u0131c\u0131ya d\xf6n\xfc\u015f\xfcr',shortDesc:'Do\u011fal yetene\u011fini, \xfczerine yans\u0131t\u0131lan beklentilerle d\u0131\u015f d\xfcnyaya \xe7\u0131kar\u0131r. Hem mahrem hem misyon insan\u0131.',longDesc:'Bu profil, hem i\xe7sel hem d\u0131\u015fsal ya\u015fam ta\u015f\u0131r. Yaln\u0131z do\u011fas\u0131nda hediyesi vard\u0131r; ama d\u0131\u015f d\xfcnyada bir "kurtar\u0131c\u0131" gibi \xe7a\u011f\u0131r\u0131l\u0131r. \u0130\xe7eride mahrem kalmak ister, d\u0131\u015far\u0131da g\xf6r\xfcn\xfcr olmak gerekir. Bu gerilimi ya\u015famak \xf6\u011fretmenidir.'},'3/5':{key:'3/5',name:'\u015eehit / Yans\u0131t\u0131c\u0131',theme:'Deneyerek \xf6\u011frendiklerini topluma sunar',shortDesc:'Hayat\u0131 bizzat deneyimleyerek \xf6\u011frenir; sonra bu pratik bilgeli\u011fi ba\u015fkalar\u0131n\u0131n krizine \xe7\xf6z\xfcm olarak sunar.',longDesc:'Bu profil, d\u0131\u015fsal olarak ya\u015far. Deneme-yan\u0131lma yoluyla bilgi toplar; bu bilgi ba\u015fkalar\u0131n\u0131n kullanmas\u0131 i\xe7indir. Yans\u0131tmalar\u0131n y\xfck\xfcn\xfc ta\u015f\u0131r; insanlar ondan beklenti y\xfckler. Pratik, problem \xe7\xf6z\xfcc\xfc ve mistik bir \xe7ekicili\u011fi vard\u0131r.'},'3/6':{key:'3/6',name:'\u015eehit / Rol Modeli',theme:'Gen\xe7 hatalar bilge bir rol modeline d\xf6n\xfc\u015f\xfcr',shortDesc:'\xdc\xe7 evreli bir ya\u015fam: ilk 30 y\u0131l deneyim, sonra \xe7at\u0131dan g\xf6zleme, sonunda rol modeli olma.',longDesc:'Bu profil, d\u0131\u015fsal olarak ya\u015far. \u0130lk yar\u0131s\u0131 denemelerle, ili\u015fki ba\u015flang\u0131\xe7lar\u0131 ve biti\u015fleriyle, kendini deniyerek ge\xe7er. 30 sonras\u0131 \xe7at\u0131dan izlemeye ge\xe7er; mesafe al\u0131r. 50 sonras\u0131 bilgeli\u011fi rol modeli olarak hayat\u0131n merkezine geri d\xf6ner.'},'4/6':{key:'4/6',name:'F\u0131rsat\xe7\u0131 / Rol Modeli',theme:'A\u011f insan\u0131, zamanla bilge bir rol modeline d\xf6n\xfc\u015f\xfcr',shortDesc:'Hayat\u0131 yak\u0131n \xe7evresi \xfczerinden ilerletirken, \xfc\xe7 evreli rol modeli yolculu\u011fu ya\u015far.',longDesc:'Bu profil, d\u0131\u015fsal olarak ya\u015far. Ba\u011flant\u0131lar\u0131 ba\u011f\u0131\u015flanm\u0131\u015f gibidir; do\u011fru ili\u015fkiler hayat\u0131n\u0131 ta\u015f\u0131r. 30 sonras\u0131 \xe7at\u0131ya \xe7ekilir, izler; 50 sonras\u0131 otantik bir rol modeli olarak topluma \xf6rnek olur.'},'4/1':{key:'4/1',name:'F\u0131rsat\xe7\u0131 / Ara\u015ft\u0131rmac\u0131',theme:'A\u011f\u0131 sa\u011flam, temelleri sabit',shortDesc:'Sabit temeller \xfczerine yak\u0131n ba\u011flar. Daha az de\u011fi\u015fen, daha kararl\u0131 ve odakl\u0131 bir yap\u0131.',longDesc:'Bu nadir bir "kal\u0131c\u0131" profilidir. Hem i\xe7sel hem d\u0131\u015fsal ya\u015far; ama her iki \xe7izgi de "sabit" niteliklidir. Kolayca d\xf6n\xfc\u015fmez; k\xf6klendi\u011fi zemin ve a\u011f \xfczerinden sa\u011flam, uzun vadeli i\u015fler kurar.'},'5/1':{key:'5/1',name:'Yans\u0131t\u0131c\u0131 / Ara\u015ft\u0131rmac\u0131',theme:'Sa\u011flam temele sahip pratik \xe7\xf6z\xfcc\xfc',shortDesc:'\xd6nce derinlemesine ara\u015ft\u0131r\u0131r, sonra d\u0131\u015far\u0131ya pratik bir uzman olarak \xe7\u0131kar. Krizlerin adam\u0131d\u0131r.',longDesc:'Bu profil, d\u0131\u015fsal olarak ya\u015far. \xdczerine yans\u0131tmalar d\xfc\u015fer; insanlar ondan \xe7\xf6z\xfcm bekler. Bunu kar\u015f\u0131layabilmek i\xe7in sa\u011flam bir bilgi temeline ihtiya\xe7 duyar. Beklenti bask\u0131s\u0131 zaman zaman a\u011f\u0131rd\u0131r; do\u011fru zamanlama hayatidir.'},'5/2':{key:'5/2',name:'Yans\u0131t\u0131c\u0131 / M\xfcnzevi',theme:'Misyonu \xe7a\u011f\u0131r\u0131r, m\xfcnzevisi geri \xe7eker',shortDesc:'D\u0131\u015far\u0131da kurtar\u0131c\u0131, i\xe7eride yaln\u0131zl\u0131\u011fa ihtiyac\u0131 olan biri. \xc7a\u011fr\u0131ld\u0131\u011f\u0131nda \xe7\u0131kar, \xe7a\u011fr\u0131lmad\u0131\u011f\u0131nda g\xf6r\xfcnmez.',longDesc:'Bu profil, d\u0131\u015fsal olarak ya\u015far ama yaln\u0131z do\u011fal yetene\u011fi vard\u0131r. Kalabal\u0131\u011fa \xe7\u0131kmak yorar; ama \xe7a\u011fr\u0131ld\u0131\u011f\u0131nda pratik \xe7\xf6z\xfcm sunar. Yaln\u0131z kalmaya hakk\u0131 kendi enerjisinin temelidir.'},'6/2':{key:'6/2',name:'Rol Modeli / M\xfcnzevi',theme:'\xc7at\u0131dan izleyen, yaln\u0131z do\u011fal hediyeli',shortDesc:'Ya\u015fam\u0131n \xfc\xe7 evresinde de yaln\u0131z zamanlar\u0131na ihtiya\xe7 duyar. Bilgeli\u011fi sessizce ta\u015f\u0131r.',longDesc:'Bu profil, hem i\xe7sel hem d\u0131\u015fsal ya\u015far. \xdc\xe7 evreli rol modeli yolculu\u011funu, yaln\u0131z do\u011fas\u0131yla birlikte y\xfcr\xfcr. Geri \xe7ekildi\u011fi y\u0131llarda kendini biriktirir; sahnede otantik olarak g\xf6r\xfcn\xfcr.'},'6/3':{key:'6/3',name:'Rol Modeli / \u015eehit',theme:'Deneyimden ge\xe7en otantik rol modeli',shortDesc:'Hayat\u0131n \xfc\xe7 evresinde de denemeye devam eder. Otantikli\u011fi "her \u015feyi g\xf6rd\xfcm" temeline dayan\u0131r.',longDesc:'Bu profil, d\u0131\u015fsal olarak ya\u015far. \u0130lk yar\u0131s\u0131 \xe7arp\u0131\u015fmalarla ge\xe7er; \xe7at\u0131dan izlerken bile denemeye devam eder. Rol modeli oldu\u011funda, bu otantiklik onun en b\xfcy\xfck g\xfcc\xfcd\xfcr: sadece konu\u015fmaz, ya\u015fam\u0131\u015ft\u0131r.'}}},428,[]);
